      const rootLogger = createLogger({ logFilePath });
      const sessionLogger = rootLogger.child({ sessionId: 'session-123' });
      const emailLogger = sessionLogger.child({ emailId: 'email-456' });

      emailLogger.info('nested context');

      await new Promise((resolve) => setTimeout(resolve, 100));

      const logContent = await fs.readFile(logFilePath, 'utf-8');
      const logLine = JSON.parse(logContent.trim());

      expect(logLine.sessionId).toBe('session-123');
      expect(logLine.emailId).toBe('email-456');
      expect(logLine.msg).toBe('nested context');
    });

    test('should merge inline metadata with child context', async () => {
      const logFilePath = join(testLogDir, 'merged-context.log');
      const logger = createLogger({ logFilePath });
      const childLogger = logger.child({ sessionId: 'session-123' });

      childLogger.info({ emailId: 'email-456', stage: 'hard-assertions' }, 'processing stage');

      await new Promise((resolve) => setTimeout(resolve, 100));

      const logContent = await fs.readFile(logFilePath, 'utf-8');
      const logLine = JSON.parse(logContent.trim());

      expect(logLine.sessionId).toBe('session-123');
      expect(logLine.emailId).toBe('email-456');
      expect(logLine.stage).toBe('hard-assertions');
      expect(logLine.msg).toBe('processing stage');
    });
  });

