/**
 * Unit Tests: Pino Logger Factory
 *
 * TDD Approach: These tests are written BEFORE implementation and MUST FAIL initially.
 * They define the contract for the pino-based logging infrastructure.
 */

import { describe, test, expect, beforeEach, afterEach, jest } from '@jest/globals';
import { promises as fs } from 'fs';
import { join } from 'path';
import { tmpdir } from 'os';

// Import will fail initially - that's expected for TDD
import { createLogger, type Logger, type LoggerOptions } from '../../src/logging/logger-factory';

describe('Pino Logger Factory', () => {
  let testLogDir: string;

  beforeEach(async () => {
    // Create temp directory for test logs
    testLogDir = join(tmpdir(), `test-logs-${Date.now()}`);
    await fs.mkdir(testLogDir, { recursive: true });
  });

  afterEach(async () => {
    // Clean up test logs
    try {
      await fs.rm(testLogDir, { recursive: true, force: true });
    } catch (error) {
      // Ignore cleanup errors
    }
  });

  describe('Logger Factory Creation', () => {
    test('should create logger with default configuration', () => {
      const logger = createLogger();

      expect(logger).toBeDefined();
      expect(logger.info).toBeInstanceOf(Function);
      expect(logger.error).toBeInstanceOf(Function);
      expect(logger.warn).toBeInstanceOf(Function);
      expect(logger.debug).toBeInstanceOf(Function);
      expect(logger.trace).toBeInstanceOf(Function);
    });

    test('should create logger with custom log level', () => {
      const logger = createLogger({ level: 'debug' });

      expect(logger).toBeDefined();
      expect(logger.level).toBe('debug');
    });

    test('should create logger with pretty-print enabled', () => {
      const logger = createLogger({ prettyPrint: true });

      expect(logger).toBeDefined();
    });

    test('should create logger with file transport', async () => {
      const logFilePath = join(testLogDir, 'test.log');
      const logger = createLogger({ logFilePath });

      logger.info('test message');

      // Give file write time to complete (pino is async)
      await new Promise((resolve) => setTimeout(resolve, 100));

      const logContent = await fs.readFile(logFilePath, 'utf-8');
      expect(logContent).toContain('test message');
    });
  });

  describe('Log Level Filtering', () => {
    test('should respect log level: info (default)', async () => {
      const logFilePath = join(testLogDir, 'level-info.log');
      const logger = createLogger({ level: 'info', logFilePath });

      logger.trace('trace message');
      logger.debug('debug message');
      logger.info('info message');
      logger.warn('warn message');
      logger.error('error message');

      await new Promise((resolve) => setTimeout(resolve, 100));

      const logContent = await fs.readFile(logFilePath, 'utf-8');
      expect(logContent).not.toContain('trace message');
      expect(logContent).not.toContain('debug message');
      expect(logContent).toContain('info message');
      expect(logContent).toContain('warn message');
      expect(logContent).toContain('error message');
    });

    test('should respect log level: debug', async () => {
      const logFilePath = join(testLogDir, 'level-debug.log');
      const logger = createLogger({ level: 'debug', logFilePath });

      logger.trace('trace message');
      logger.debug('debug message');
      logger.info('info message');

      await new Promise((resolve) => setTimeout(resolve, 100));

      const logContent = await fs.readFile(logFilePath, 'utf-8');
      expect(logContent).not.toContain('trace message');
      expect(logContent).toContain('debug message');
      expect(logContent).toContain('info message');
    });

    test('should respect log level: error (only errors)', async () => {
      const logFilePath = join(testLogDir, 'level-error.log');
      const logger = createLogger({ level: 'error', logFilePath });

      logger.debug('debug message');
      logger.info('info message');
      logger.warn('warn message');
      logger.error('error message');

      await new Promise((resolve) => setTimeout(resolve, 100));

      const logContent = await fs.readFile(logFilePath, 'utf-8');
      expect(logContent).not.toContain('debug message');
      expect(logContent).not.toContain('info message');
      expect(logContent).not.toContain('warn message');
      expect(logContent).toContain('error message');
    });
  });

  describe('Transport Configuration', () => {
    test('should support console-only transport (no file)', () => {
      const logger = createLogger({ enableConsole: true });

      expect(logger).toBeDefined();
      logger.info('console only');
      // No file should be created
    });

    test('should support file-only transport (no console)', async () => {
      const logFilePath = join(testLogDir, 'file-only.log');
      const logger = createLogger({ enableConsole: false, logFilePath });

      logger.info('file only');

      await new Promise((resolve) => setTimeout(resolve, 100));

      const logContent = await fs.readFile(logFilePath, 'utf-8');
      expect(logContent).toContain('file only');
    });

    test('should support dual transport (console + file)', async () => {
      const logFilePath = join(testLogDir, 'dual-transport.log');
      const logger = createLogger({ enableConsole: true, logFilePath });

      logger.info('dual transport message');

      await new Promise((resolve) => setTimeout(resolve, 100));

      const logContent = await fs.readFile(logFilePath, 'utf-8');
      expect(logContent).toContain('dual transport message');
    });
  });

  describe('Output Format', () => {
    test('should output JSON format by default', async () => {
      const logFilePath = join(testLogDir, 'json-format.log');
      const logger = createLogger({ logFilePath, prettyPrint: false });

      logger.info({ emailId: '123', action: 'classify' }, 'processing email');

      await new Promise((resolve) => setTimeout(resolve, 100));

      const logContent = await fs.readFile(logFilePath, 'utf-8');
      const logLine = JSON.parse(logContent.trim());

      expect(logLine.level).toBe(30); // info level
      expect(logLine.msg).toBe('processing email');
      expect(logLine.emailId).toBe('123');
      expect(logLine.action).toBe('classify');
    });

    test('should support pretty-print format for development', async () => {
      const logFilePath = join(testLogDir, 'pretty-format.log');
      const logger = createLogger({ logFilePath, prettyPrint: true });

      logger.info('pretty printed message');

      await new Promise((resolve) => setTimeout(resolve, 100));

      const logContent = await fs.readFile(logFilePath, 'utf-8');
      // Pretty format is human-readable, not JSON
      expect(() => JSON.parse(logContent.trim())).toThrow();
      expect(logContent).toContain('pretty printed message');
    });
  });

  describe('Contextual Metadata', () => {
    test('should support child logger with automatic context', async () => {
      const logFilePath = join(testLogDir, 'child-logger.log');
      const parentLogger = createLogger({ logFilePath });
      const childLogger = parentLogger.child({ sessionId: 'session-123' });

      childLogger.info('child log message');

      await new Promise((resolve) => setTimeout(resolve, 100));

      const logContent = await fs.readFile(logFilePath, 'utf-8');
      const logLine = JSON.parse(logContent.trim());

      expect(logLine.sessionId).toBe('session-123');
      expect(logLine.msg).toBe('child log message');
    });

    test('should support nested child loggers', async () => {
      const logFilePath = join(testLogDir, 'nested-child.log');
      const rootLogger = createLogger({ logFilePath });
      const sessionLogger = rootLogger.child({ sessionId: 'session-123' });
      const emailLogger = sessionLogger.child({ emailId: 'email-456' });

      emailLogger.info('nested context');

      await new Promise((resolve) => setTimeout(resolve, 100));

      const logContent = await fs.readFile(logFilePath, 'utf-8');
      const logLine = JSON.parse(logContent.trim());

      expect(logLine.sessionId).toBe('session-123');
      expect(logLine.emailId).toBe('email-456');
      expect(logLine.msg).toBe('nested context');
    });

    test('should merge inline metadata with child context', async () => {
      const logFilePath = join(testLogDir, 'merged-context.log');
      const logger = createLogger({ logFilePath });
      const childLogger = logger.child({ sessionId: 'session-123' });

      childLogger.info({ emailId: 'email-456', stage: 'hard-assertions' }, 'processing stage');

      await new Promise((resolve) => setTimeout(resolve, 100));

      const logContent = await fs.readFile(logFilePath, 'utf-8');
      const logLine = JSON.parse(logContent.trim());

      expect(logLine.sessionId).toBe('session-123');
      expect(logLine.emailId).toBe('email-456');
      expect(logLine.stage).toBe('hard-assertions');
      expect(logLine.msg).toBe('processing stage');
    });
  });

  describe('Environment Variable Integration', () => {
    test('should respect LOG_LEVEL environment variable', () => {
      const originalLogLevel = process.env.LOG_LEVEL;

      try {
        process.env.LOG_LEVEL = 'debug';
        const logger = createLogger();

        expect(logger.level).toBe('debug');
      } finally {
        if (originalLogLevel !== undefined) {
          process.env.LOG_LEVEL = originalLogLevel;
        } else {
          delete process.env.LOG_LEVEL;
        }
      }
    });

    test('should use default level if LOG_LEVEL not set', () => {
      const originalLogLevel = process.env.LOG_LEVEL;

      try {
        delete process.env.LOG_LEVEL;
        const logger = createLogger();

        expect(logger.level).toBe('info'); // Default level
      } finally {
        if (originalLogLevel !== undefined) {
          process.env.LOG_LEVEL = originalLogLevel;
        }
      }
    });

    test('should allow explicit level to override LOG_LEVEL', () => {
      const originalLogLevel = process.env.LOG_LEVEL;

      try {
        process.env.LOG_LEVEL = 'debug';
        const logger = createLogger({ level: 'error' });

        expect(logger.level).toBe('error'); // Explicit override wins
      } finally {
        if (originalLogLevel !== undefined) {
          process.env.LOG_LEVEL = originalLogLevel;
        } else {
          delete process.env.LOG_LEVEL;
        }
      }
    });
  });

  describe('Per-Run Log File Creation', () => {
    test('should create log file with timestamp in filename', async () => {
      const logFilePath = join(testLogDir, `run-${Date.now()}.log`);
      const logger = createLogger({ logFilePath });

      logger.info('per-run log');

      await new Promise((resolve) => setTimeout(resolve, 100));

      const fileExists = await fs
        .access(logFilePath)
        .then(() => true)
        .catch(() => false);
      expect(fileExists).toBe(true);
    });

    test('should create log directory if it does not exist', async () => {
      const nestedLogDir = join(testLogDir, 'nested', 'logs');
