/**
 * Pino Logger Factory
 *
 * Provides structured, high-performance logging with:
 * - Multiple transports (console + file)
 * - Log level filtering via environment variable
 * - JSON and pretty-print output modes
 * - Child loggers with automatic context propagation
 * - Async non-blocking writes
 *
 * Replaces custom DualLogger and ConsoleInterceptor (~400 LOC).
 */

import pino from 'pino';
import { promises as fs } from 'fs';
import { dirname } from 'path';

/**
 * Pino logger instance with child logger support
 */
export type Logger = pino.Logger;

/**
 * Configuration options for logger creation
 */
export interface LoggerOptions {
  /**
   * Log level (default: 'info' or LOG_LEVEL env var)
   * Levels: 'trace', 'debug', 'info', 'warn', 'error', 'fatal'
   */
  level?: pino.Level;

  /**
   * Enable console output (default: true)
   */
  enableConsole?: boolean;

  /**
   * Path to log file (optional)
   * If provided, logs will be written to this file asynchronously
   */
  logFilePath?: string;

  /**
   * Enable pretty-print mode for human-readable output (default: false)
   * Recommended for development, disable in production for JSON logs
   */
  prettyPrint?: boolean;
}

/**
 * Create a configured pino logger instance
 *
 * @param options - Logger configuration options
 * @returns Pino logger instance
 *
 * @example
 * // Console-only logger with default level (info)
 * const logger = createLogger();
 * logger.info('message');
 *
 * @example
 * // File + console logger with debug level
 * const logger = createLogger({
 *   level: 'debug',
 *   logFilePath: './logs/app.log'
 * });
 *
 * @example
 * // Pretty-print for development
 * const logger = createLogger({ prettyPrint: true });
 *
 * @example
 * // Child logger with automatic context
 * const rootLogger = createLogger();
 * const sessionLogger = rootLogger.child({ sessionId: '123' });
 * sessionLogger.info('auto includes sessionId');
 */
export function createLogger(options: LoggerOptions = {}): Logger {
  const {
    level = (process.env.LOG_LEVEL as pino.Level) || 'info',
    enableConsole = true,
    logFilePath,
    prettyPrint = false,
  } = options;

  // Base logger configuration
  const pinoOptions: pino.LoggerOptions = {
    level,
  };

  // Determine destination(s)
  const destinations: pino.StreamEntry[] = [];

  // Console transport
  if (enableConsole) {
    if (prettyPrint) {
      // Pretty-print transport for development
      destinations.push({
        level,
        stream: pino.transport({
          target: 'pino-pretty',
          options: {
            colorize: true,
            translateTime: 'SYS:standard',
            ignore: 'pid,hostname',
          },
        }),
      });
    } else {
      // JSON output to stdout
      destinations.push({
        level,
        stream: process.stdout,
      });
    }
  }

  // File transport (async)
  if (logFilePath) {
    // Ensure log directory exists (sync for simplicity during initialization)
    const logDir = dirname(logFilePath);
    fs.mkdir(logDir, { recursive: true }).catch((error) => {
      // Silently fail if directory creation fails - logger will handle write errors
      console.error(`Failed to create log directory ${logDir}:`, error);
    });

    if (prettyPrint) {
      // Pretty-print to file
      destinations.push({
        level,
        stream: pino.transport({
          target: 'pino-pretty',
          options: {
            destination: logFilePath,
            colorize: false,
            translateTime: 'SYS:standard',
            ignore: 'pid,hostname',
            mkdir: true,
          },
        }),
      });
    } else {
      // JSON output to file
      destinations.push({
        level,
        stream: pino.destination({
          dest: logFilePath,
          sync: false, // Async writes for performance
          mkdir: true,
        }),
      });
    }
  }

  // Handle edge case: no transports configured
  if (destinations.length === 0) {
    // Fallback to stdout
    destinations.push({
      level,
      stream: process.stdout,
    });
  }

  // Create multi-stream logger if multiple destinations
  if (destinations.length > 1) {
    return pino(
      pinoOptions,
      pino.multistream(destinations, {
        dedupe: true, // Prevent duplicate logs across streams
      })
    );
  }

  // Single destination
  return pino(pinoOptions, destinations[0].stream);
}

